+const resolveOracleInlineCookiesFile = (): string | undefined => {
+  const oracleDir = path.join(os.homedir(), '.oracle');
+  for (const filename of ORACLE_COOKIE_FILES) {
+    const candidate = path.join(oracleDir, filename);
